const SCROLL_THRESHOLD = 40;

export function ThreadDetailView() {
  const { projectId, threadId } = useParams<{
    projectId: string
    threadId: string
  }>();
  const { data: thread, isLoading, error } = useThread(threadId ?? "");
  const { data: events } = useThreadEvents(threadId ?? "");
  const { debugMode } = useDebugMode();
  const tellThread = useTellThread();
  const stopThread = useStopThread();
  const promptDraft = usePromptDraftStorage({ projectId, threadId });
  const message = promptDraft.value;
  const [showScrollToLatest, setShowScrollToLatest] = useState(false);
  const {
    selectedModel,
    setSelectedModel,
    reasoningLevel,
    setReasoningLevel,
    activeModel,
    modelOptions,
    reasoningOptions,
  } = usePromptModelReasoning();
  const conversationEvents = useMemo(
    () =>
      debugMode
        ? (events ?? []).filter(
            (event) => !normalizeEventType(event.type).includes("delta"),
          )
        : projectThreadConversation(events, { includeStreamingDeltas: false }),
    [debugMode, events],
  );
  const { containerRef, handleScroll: baseHandleScroll } = useAutoScroll(
    conversationEvents.length,
  );
  const latestAgentMessageIndex = useMemo(() => {
    for (let index = conversationEvents.length - 1; index >= 0; index -= 1) {
      const event = conversationEvents[index];
      if (event && isAgentConversationEvent(event)) return index;
    }
    return -1;
  }, [conversationEvents]);

  const handleScroll = useCallback(() => {
    baseHandleScroll();
    const el = containerRef.current;
    if (!el) return;
    const distanceFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
    setShowScrollToLatest(distanceFromBottom > SCROLL_THRESHOLD);
  }, [baseHandleScroll, containerRef]);

  const scrollToLatest = useCallback(() => {
    const el = containerRef.current;
    if (!el) return;
    el.scrollTop = el.scrollHeight;
    setShowScrollToLatest(false);
  }, [containerRef]);

  if (!projectId || !threadId) {
    return <p className="text-sm text-destructive py-12 text-center">Not found</p>;
  }
  if (isLoading) return <p className="text-sm text-muted-foreground py-12 text-center">Loading...</p>;
  if (
    error ||
    !thread ||
    thread.projectId !== projectId
  ) {
    return (
      <p className="text-sm text-destructive py-12 text-center">
        {error ? error.message : "Not found"}
      </p>
    );
  }

  const canSendFollowUp = true;
  const promptPlaceholder =
    thread.status === "idle"
      ? "Ask for follow-up changes"
      : "Send a message to this thread...";

  const handleSend = () => {
    const trimmed = message.trim();
    if (!trimmed) return;
    tellThread.mutate(
      {
        id: thread.id,
        input: [{ type: "text", text: trimmed }],
        model: activeModel?.model ?? selectedModel,
        reasoningLevel,
      },
      { onSuccess: () => promptDraft.clear() },
    );
  };

  return (
    <div className="-mx-4 -mt-4 flex h-full min-h-0 flex-1 flex-col overflow-hidden md:-mx-5 md:-mt-5">
      <div className="relative flex min-h-0 flex-1 flex-col overflow-hidden">
        <div
          ref={containerRef}
          onScroll={handleScroll}
          className="min-h-0 flex-1 overflow-y-auto"
        >
          <div className="mx-auto flex w-full max-w-[800px] flex-col gap-1 px-4 pb-4 pt-2">
            {conversationEvents.length === 0 ? (
              <div className="py-16 text-center text-sm text-muted-foreground">
                No events yet
              </div>
            ) : (
              conversationEvents.map((event, index) => (
                <ConversationEntry
                  key={event.id}
                  event={event}
                  isLatestAgentMessage={index === latestAgentMessageIndex}
                  showRawFallback={debugMode}
                />
              ))
            )}
            {thread.status === "active" ? <ConversationWorkingIndicator /> : null}
          </div>
        </div>

        <div className="shrink-0">
          <div className="chat-prompt-box mx-auto w-full max-w-[800px] bg-background px-4 pb-4">
            <div className="flex h-0 items-center justify-center">
              <button
                onClick={scrollToLatest}
                className={cn(
                  "z-20 -mt-20 flex size-8 items-center justify-center rounded-full border border-foreground/20 bg-background/80 shadow-md backdrop-blur-md transition-all duration-200 hover:border-foreground/30 hover:bg-background/90",
                  showScrollToLatest
                    ? "translate-y-0 opacity-100"
                    : "pointer-events-none translate-y-2 opacity-0",
                )}
                aria-label="Scroll to latest event"
                type="button"
              >
                <ArrowDown className="size-4" />
              </button>
            </div>
            <PromptBox
              value={message}
              onChange={promptDraft.setValue}
              onSubmit={handleSend}
              onStop={
                thread.status === "active"
                  ? () => stopThread.mutate(thread.id)
                  : undefined
              }
              isSubmitting={tellThread.isPending}
              submitDisabled={!canSendFollowUp}
              isRunning={thread.status === "active"}
              placeholder={promptPlaceholder}
              submitMode="enter"
              autoFocus
              footerStart={
                <>
                  <PromptOptionPicker
                    label="Model"
                    value={activeModel?.model ?? selectedModel}
                    options={modelOptions}
                    onChange={setSelectedModel}
                  />
                  <PromptOptionPicker
                    label="Reasoning"
                    value={reasoningLevel}
                    options={reasoningOptions}
                    onChange={setReasoningLevel}
                  />
                </>
              }
            />
          </div>
        </div>
      </div>
    </div>
  );
}

